#include <algorithm>

void quicksort(std::vector<int>& arr, int low, int high);

void adaptive_sort(std::vector<int>& arr) {
    int n = arr.size();
    if (n < 2) return;
    bool s = 1, r = 1;
    for (int i = 1; i < n && (s || r); ++i) {
        if (arr[i] < arr[i - 1]) s = 0;
        else if (arr[i] > arr[i - 1]) r = 0;
    }
    if (s) return;
    if (r) { std::reverse(arr.begin(), arr.end()); return; }
    quicksort(arr, 0, n - 1);
}

void quicksort(std::vector<int>& arr, int low, int high) {
    while (low < high) {
        if (high - low < 32) {
            for (int i = low + 1; i <= high; ++i) {
                int v = arr[i], j = i;
                if (v < arr[j - 1]) {
                    while (j > low && arr[j - 1] > v) { arr[j] = arr[j - 1]; --j; }
                    arr[j] = v;
                }
            }
            return;
        }
        int m = low + (high - low) / 2;
        if (arr[m] < arr[low]) std::swap(arr[m], arr[low]);
        if (arr[high] < arr[low]) std::swap(arr[high], arr[low]);
        if (arr[high] < arr[m]) std::swap(arr[high], arr[m]);
        int p = arr[m], i = low - 1, j = high + 1;
        while (1) {
            while (arr[++i] < p);
            while (arr[--j] > p);
            if (i >= j) break;
            std::swap(arr[i], arr[j]);
        }
        if (j - low < high - j) { quicksort(arr, low, j); low = j + 1; }
        else { quicksort(arr, j + 1, high); high = j; }
    }
}

